	import java.util.*;
	import sailpoint.api.*;
	import sailpoint.object.*;
	
	import java.io.BufferedReader;
	import java.io.FileNotFoundException;
	import java.io.FileReader;
	import java.io.IOException;
	import java.util.ArrayList;
	import java.util.List;

    List maList =new ArrayList();
	String csvFileName = "\\\\andc1wapp0147.ds.sjhs.com\\IIQDataFiles\\PROD-ManagedAttributes-Delete-Full-List.csv";
	public static List readCSV() throws FileNotFoundException, IOException {
        List rows = new ArrayList();
        BufferedReader br = new BufferedReader(new FileReader(csvFileName));
        String line = "";
        String headerline = br.readLine(); 
        while((line = br.readLine()) != null) { 
           rows.add(line);
        }
             br.close(); 
             return rows;
    
	}
     maList = readCSV();
  
     int counter=0;
     String[] masterSplit=null;
     Filter filter=null;
     ManagedAttribute mgd=null;
     List outList = new ArrayList();
     for(String splitStr:maList){
         masterSplit=null;
         masterSplit=splitStr.split("##");
         Map map=null;
         if(masterSplit.length==2){
             filter=null;
             mgd=null;
filter=Filter.ignoreCase(Filter.and(Filter.eq("id",masterSplit[0]),Filter.eq("application.id",masterSplit[1])));
mgd=context.getUniqueObject(ManagedAttribute.class,filter);
             if(mgd!=null){
			 						Terminator t = new Terminator(context);
                 t.deleteObject(mgd);
                 
                 counter++;
                 if(counter%50==0){
                     context.commitTransaction();
                 }
             }
         }
     }
     if(counter>0){
         context.commitTransaction();
     }

     return "Success";
